sql:
SELECT COUNT(*), MAX(total_wins)
FROM team_performance
WHERE season_id = 0;

SELECT AVG(tp.total_wins) AS avg_wins_per_team
FROM (
    SELECT DISTINCT m.match_winner_id AS team_id
    FROM matches m
) victorious_teams
JOIN team_performance tp ON victorious_teams.team_id = tp.team_id;

SELECT total_wins
FROM team_performance
WHERE total_wins > 5;

SELECT AVG(total_wins) AS average_wins
FROM team_performance
WHERE total_wins > 5;

SELECT SUM(total_wins) AS total_chennai_super_kings_wins
FROM team_performance
WHERE team_id = (SELECT team_id FROM teams WHERE team_name = 'Chennai Super Kings');

SELECT team_name, total_players
FROM teams
WHERE total_players = (SELECT MAX(total_players) FROM teams);

SELECT DISTINCT t.team_name, t.sponsor
FROM teams t
INNER JOIN matches m ON t.team_id = m.match_winner_id;
